        if len(parts) > 1:
            service_part = parts[1].split('.')[0]
            items = re.split(r',|\s+and\s+|&', service_part)
            for item in items:
                cleaned = item.strip().rstrip('.').strip('"\'')
                if cleaned and len(cleaned) < 100 and 'located at' not in cleaned.lower():
                    categories.append(cleaned)

    if 'services including' in desc_lower:
        parts = desc.split('services including')
        if len(parts) > 1:
            service_part = parts[1].split('.')[0]
            items = re.split(r',|\s+and\s+|&', service_part)
            for item in items:
                cleaned = item.strip().rstrip('.').strip('"\'')
                if cleaned and len(cleaned) < 100:
                    categories.append(cleaned)

    return list(set([c for c in categories if c and len(c) > 5]))

